// Compare the fused GDN kernel against a numpy reference for Qwen3.5 layer 0.
//
// Loads the 8 fused-op inputs + expected output from /tmp/qwen35_ref/*.f32
// (generated by tests/dump_qwen35_ref_np.py), runs kernel_gdn_prefill, and
// compares the output + final state against the reference.
//
// This validates the fused kernel's math against an independent numpy
// implementation that uses the real Qwen3.5 layer-0 weights.

#include "kernels/gdn.h"
#include "graph/graph.h"
#include "kernels/tensor.h"
#include <cmath>
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <string>
#include <vector>

static int failures = 0;

static float* load_f32(const char* path, int expected_count) {
    FILE* f = fopen(path, "rb");
    if (!f) { fprintf(stderr, "Cannot open %s\n", path); return nullptr; }
    float* data = new float[expected_count];
    size_t n = fread(data, sizeof(float), expected_count, f);
    fclose(f);
    if ((int)n != expected_count) {
        fprintf(stderr, "Short read %s: got %zu expected %d\n", path, n, expected_count);
        delete[] data;
        return nullptr;
    }
    return data;
}

static bool compare(const float* a, const float* b, int n, const char* name, float tol = 1e-4) {
    float max_err = 0; int max_idx = 0;
    for (int i = 0; i < n; i++) {
        float err = fabsf(a[i] - b[i]);
        if (err > max_err) { max_err = err; max_idx = i; }
    }
    if (max_err > tol) {
        fprintf(stderr, "  MISMATCH %s: max_err=%e at idx %d (ref=%f got=%f)\n",
                name, max_err, max_idx, a[max_idx], b[max_idx]);
        failures++;
        return false;
    }
    printf("  PASS: %s (max_err=%e at idx %d)\n", name, max_err, max_idx);
    return true;
}

int main() {
    const int num_heads = 16, k_dim = 128, v_dim = 128, seq_len = 4;
    const int qkv_total = num_heads * k_dim * 3;  // 6144
    const int z_dim = num_heads * v_dim;          // 2048
    const int state_size = num_heads * k_dim * v_dim;  // 16 * 16384

    const char* D = "/tmp/qwen35_ref";
    std::string p_qkv   = std::string(D) + "/qkv_conv.f32";
    std::string p_a     = std::string(D) + "/a_out.f32";
    std::string p_b     = std::string(D) + "/b_out.f32";
    std::string p_z     = std::string(D) + "/z_out.f32";
    std::string p_alog  = std::string(D) + "/A_log.f32";
    std::string p_dtb   = std::string(D) + "/dt_bias.f32";
    std::string p_normw = std::string(D) + "/norm_weight.f32";
    std::string p_out   = std::string(D) + "/fused_out.f32";
    std::string p_state = std::string(D) + "/state_final.f32";
    float* ref_qkv    = load_f32(p_qkv.c_str(),   seq_len * qkv_total);
    float* ref_a      = load_f32(p_a.c_str(),     seq_len * num_heads);
    float* ref_b      = load_f32(p_b.c_str(),     seq_len * num_heads);
    float* ref_z      = load_f32(p_z.c_str(),     seq_len * z_dim);
    float* ref_A_log  = load_f32(p_alog.c_str(),  num_heads);
    float* ref_dtb    = load_f32(p_dtb.c_str(),   num_heads);
    float* ref_normw  = load_f32(p_normw.c_str(), v_dim);
    float* ref_out    = load_f32(p_out.c_str(),   seq_len * z_dim);
    float* ref_state  = load_f32(p_state.c_str(), state_size);
    if (!ref_qkv) { printf("Run tests/dump_qwen35_ref_np.py first!\n"); return 1; }

    // Kernel state (init to zero, matches numpy reference).
    float* state_k = new float[state_size]();
    float* out_k   = new float[seq_len * z_dim]();

    // Build tensors. Declared shape uses [dim, seq] convention; kernel indexes
    // by data layout [seq, dim] directly. Strides are set by Tensor::create to
    // match the declared shape, but the kernel does not consult them.
    auto make = [](Precision prec, int d0, int d1, void* data) {
        return Tensor::create(prec, MemoryType::EXTERNAL, d0, d1, 1, 1, data);
    };
    Tensor qkv_t   = make(Precision::FP32, qkv_total, seq_len,  ref_qkv);
    Tensor a_t     = make(Precision::FP32, num_heads,  seq_len, ref_a);
    Tensor b_t     = make(Precision::FP32, num_heads,  seq_len, ref_b);
    Tensor z_t     = make(Precision::FP32, z_dim,      seq_len, ref_z);
    Tensor A_log_t = make(Precision::FP32, num_heads,  1,       ref_A_log);
    Tensor dtb_t   = make(Precision::FP32, num_heads,  1,       ref_dtb);
    Tensor norm_t  = make(Precision::FP32, v_dim,      1,       ref_normw);
    Tensor state_t = make(Precision::FP32, state_size, 1,       state_k);
    Tensor out_t   = make(Precision::FP32, z_dim,      seq_len, out_k);

    OpParams params;
    params.i32 = {num_heads, k_dim, v_dim, seq_len, 1 /*use_l2norm*/, 4 /*conv_kernel*/};
    params.f32 = {1e-6f /*rms_eps*/, 1e-6f /*l2norm_eps*/, 1.f / std::sqrt((float)k_dim)};

    std::vector<const Tensor*> inputs = {&qkv_t, &a_t, &b_t, &z_t,
                                          &A_log_t, &dtb_t, &norm_t, &state_t};
    std::vector<Tensor*> outputs = {&out_t};
    kernel_gdn_prefill(params, inputs, outputs, nullptr);

    // Compare fused output (RMSNormGated result), [seq, z_dim] row-major.
    compare(ref_out, out_k, seq_len * z_dim, "fused_out");
    // Compare final recurrent state.
    compare(ref_state, state_k, state_size, "state_final", 1e-4f);

    printf("\n");
    printf("  ref out[0,:3] = %.4e %.4e %.4e\n", ref_out[0], ref_out[1], ref_out[2]);
    printf("  k   out[0,:3] = %.4e %.4e %.4e\n", out_k[0], out_k[1], out_k[2]);
    printf("  ref state[0,:3] = %.4e %.4e %.4e\n", ref_state[0], ref_state[1], ref_state[2]);
    printf("  k   state[0,:3] = %.4e %.4e %.4e\n", state_k[0], state_k[1], state_k[2]);

    delete[] ref_qkv; delete[] ref_a; delete[] ref_b; delete[] ref_z;
    delete[] ref_A_log; delete[] ref_dtb; delete[] ref_normw;
    delete[] ref_out; delete[] ref_state;
    delete[] state_k; delete[] out_k;

    printf(failures ? "\n%d FAILED\n" : "\nAll comparisons passed!\n", failures);
    return failures;
}
